import requests
from typing import List, Dict

class ReleaseNoteGenerator:
    def __init__(self, api_url: str, api_key: str):
        self.api_url = api_url
        self.api_key = api_key
        self.headers = {'Authorization': f'Bearer {api_key}'}

    def fetch_tickets(self) -> List[Dict]:
        response = requests.get(self.api_url, headers=self.headers)
        response.raise_for_status()
        return response.json()

    def filter_tickets(self, tickets: List[Dict]) -> List[Dict]:
        filtered_tickets = []
        for ticket in tickets:
            if ticket.get('type') == 'security':
                filtered_tickets.append(ticket)
            elif ticket.get('status') != 'WIP' and ticket.get('status') != 'refactor':
                filtered_tickets.append(ticket)
        return filtered_tickets

    def generate_release_note(self, filtered_tickets: List[Dict]) -> str:
        release_note = "# Release Notes\n\n"
        for ticket in filtered_tickets:
            if ticket.get('type') == 'security':
                release_note += f"**Security Patch**: {ticket['title']}\n\n"
            else:
                release_note += f"- {ticket['title']} (Ticket ID: {ticket['id']})\n\n"
        return release_note

# Example usage
api_url = "https://api.example.com/tickets"
api_key = "your-api-key"
generator = ReleaseNoteGenerator(api_url, api_key)
tickets = generator.fetch_tickets()
filtered_tickets = generator.filter_tickets(tickets)
release_note = generator.generate_release_note(filtered_tickets)
print(release_note)


This workflow:
1. Fetches tickets from an API.
2. Filters tickets to include only security patches and exclude 'WIP' or 'refactor' tickets.
3. Generates a release note with the filtered tickets, formatting security patches differently from other tickets.
